import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface FeaturedDish {
  name: string;
  price: number;
  rating: number;
}

interface MenuData {
  featuredDishes: FeaturedDish[];
}

export default function Widget() {
  const menuData = response.data.data as MenuData;
  const { featuredDishes } = menuData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: '#FF5722' }}>Featured Dishes</Typography>
          {featuredDishes.map((dish, index) => (
            <Box key={index} sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <Box>
                <Typography variant="body1" sx={{ fontWeight: 600 }}>{dish.name}</Typography>
                <Typography variant="body2" color="text.secondary">Rating: {dish.rating}</Typography>
              </Box>
              <Chip label={`$${dish.price.toFixed(2)}`} sx={{ bgcolor: '#FFC107', color: '#FFFFFF', fontWeight: 600 }} />
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
